public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {
        PotionShop shop = new PotionShop();
        String[] potions = {"Health Potion", "Mana Elixir", "Speed Brew"};

        // ── parsePrice: valid input ──
        check("parsePrice valid", "9.99",
              String.valueOf(shop.parsePrice("9.99")));

        check("parsePrice integer string", "50.0",
              String.valueOf(shop.parsePrice("50")));

        // ── parsePrice: invalid input ──
        check("parsePrice invalid returns -1", "-1.0",
              String.valueOf(shop.parsePrice("lots")));

        check("parsePrice empty string returns -1", "-1.0",
              String.valueOf(shop.parsePrice("")));

        // ── getPotionName: valid index ──
        check("getPotionName index 0", "Health Potion",
              shop.getPotionName(potions, 0));

        check("getPotionName index 2", "Speed Brew",
              shop.getPotionName(potions, 2));

        // ── getPotionName: out of bounds ──
        check("getPotionName index 5 returns Unknown", "Unknown",
              shop.getPotionName(potions, 5));

        check("getPotionName index -1 returns Unknown", "Unknown",
              shop.getPotionName(potions, -1));

        // ── countLetters: valid word ──
        check("countLetters normal word", "6",
              String.valueOf(shop.countLetters("potion")));

        check("countLetters empty string", "0",
              String.valueOf(shop.countLetters("")));

        // ── countLetters: null ──
        check("countLetters null returns 0", "0",
              String.valueOf(shop.countLetters(null)));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
}
